def set_device_state(action):
    if machine is None:
        return {"ok": True, "action": action}
    if action == "turn_on":
        try:
            pin = machine.Pin(2, machine.Pin.OUT)
            pin.value(1)
        except Exception:
            pass
        return {"ok": True, "action": action}
    if action == "turn_off":
        try:
            pin = machine.Pin(2, machine.Pin.OUT)
            pin.value(0)
        except Exception:
            pass
        return {"ok": True, "action": action}
    if action == "status":
        try:
            pin = machine.Pin(2, machine.Pin.OUT)
            return {"ok": True, "action": action, "state": pin.value()}
        except Exception:
            return {"ok": True, "action": action}
    return {"ok": False, "error": "unknown_action", "action": action}

