def connect_wifi(ssid, password, timeout=20):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        for _ in range(timeout * 2):
            if wlan.isconnected():
                break
            import time
            time.sleep(0.5)
    return wlan

